{"code": "import json, re

businesses = var_functions.query_db:30
print('Total:', len(businesses))

wifi_bus = []
for b in businesses:
    attrs = b.get('attributes', {})
    if isinstance(attrs, dict) and attrs.get('WiFi'):
        wifi = str(attrs.get('WiFi'))
        desc = b.get('description', '')
        m = re.search(r',\s*([A-Z]{2})\b', desc)
        if m:
            wifi_bus.append({'id': b['business_id'], 'state': m.group(1), 'wifi': wifi})

print('WiFi businesses:', len(wifi_bus))

s_counts = {}
for wb in wifi_bus:
    s_counts[wb['state']] = s_counts.get(wb['state'], 0) + 1

print('State counts:', list(s_counts.items())[:10])

result = {'total_wifi': len(wifi_bus), 'state_counts': s_counts, 'wifi_bus': wifi_bus[:10]}
print('__RESULT__:')
print(json.dumps(result))"}

